import path from "node:path";
import { formatDevBuildStatusLine, getDevBuildSummary, isDevBuildActive, readBuildInfo, } from "../buildInfo.js";
import { getConfig, hasCredentials } from "../config.js";
import { checkForUpdate, formatStaleMessage, formatUpdateMessage, } from "../updates.js";
export async function runStatus(currentVersion, platform, pluginRoot, scriptUrl) {
    const config = getConfig();
    const devBuildActive = isDevBuildActive(platform, scriptUrl);
    // The running build's commit, read from the vendored dist/buildInfo.json.
    // Lets checkForUpdate detect a stale cache served under the same version.
    const localBuildInfo = pluginRoot
        ? readBuildInfo(path.join(pluginRoot, "dist"))
        : null;
    const { current, latest, updateAvailable, staleSameVersion } = await checkForUpdate(currentVersion, platform, localBuildInfo?.gitSha);
    console.log(`Plugin: ${devBuildActive ? "Bitfab Dev" : "Bitfab"}`);
    console.log(`Service URL: ${config.serviceUrl}`);
    let versionSuffix = "";
    if (updateAvailable && staleSameVersion) {
        versionSuffix = ` (${formatStaleMessage(platform)})`;
    }
    else if (updateAvailable && latest) {
        versionSuffix = ` (${formatUpdateMessage(latest, platform)})`;
    }
    console.log(`Version: v${current}${versionSuffix}`);
    if (devBuildActive && pluginRoot) {
        const summary = getDevBuildSummary(pluginRoot);
        if (summary) {
            console.log(formatDevBuildStatusLine(summary));
            console.log(`Plugin path: ${summary.pluginRoot}`);
        }
    }
    else if (localBuildInfo?.gitSha) {
        // Prod install: surface the build commit so a stale cache is visible even
        // when the version string matches the latest release.
        console.log(`Build: ${localBuildInfo.gitSha.slice(0, 7)}`);
    }
    if (!hasCredentials()) {
        console.log("Status: not authenticated");
        console.log(`\nRun ${platform.loginHint} to authenticate.`);
        return;
    }
    let verified = false;
    try {
        const res = await fetch(`${config.serviceUrl}/api/plugin/whoami`, {
            headers: { Authorization: `Bearer ${config.apiKey}` },
        });
        verified = res.ok;
    }
    catch { }
    if (!verified) {
        console.log("Status: not authenticated (key invalid for current server)");
        console.log(`\nRun ${platform.loginHint} to re-authenticate.`);
        return;
    }
    console.log("Status: authenticated");
}
